#include<bits/stdc++.h>
using namespace std;
struct node
{
    int sum,f,son[2],val,num,h,tag,rev;
}t[1000010];
int cnt,root;
void pushrev(int x)
{
    if(x==0)
    {
        return;
    }
    t[x].tag^=1;
    swap(t[x].son[0],t[x].son[1]);
}
void pushdown(int x)
{
    if(!x)
    {
        return;
    }
    int tg=t[x].tag;
    if(tg)
    {
        pushrev(t[x].son[0]);
        pushrev(t[x].son[1]);
        t[x].tag=0;
    }
}
void pushup(int x)
{
    if(x==0)
    {
        return;
    }
    t[x].sum=t[t[x].son[0]].sum+t[x].num+t[t[x].son[1]].sum;
    t[x].h=max(t[t[x].son[0]].h,t[t[x].son[1]].h)+1;
}
void rotate(int x)
{
    if(!x)
    {
        return;
    }
    int f=t[x].f,g=t[f].f,c=(t[f].son[0]==x);
    t[t[x].son[c]].f=f;
    t[f].son[!c]=t[x].son[c];
    t[x].f=g;
    t[g].son[t[g].son[1]==f]=x;
    t[f].f=x;
    t[x].son[c]=f;
    pushup(f);
    pushup(x);
    if(g==0)
    {
        root=x;
    }
}
void splay(int x)
{
    while(x!=root)
    {
        pushdown(t[t[x].f].f);
        pushdown(t[x].f);
        pushdown(x);
        if(t[x].f==root)
        {
            rotate(x);
            continue;
        }
        if(t[t[x].f].f==root||(t[t[x].f].son[0]==x)^(t[t[t[x].f].f].son[0]==t[x].f))
        {
            rotate(x);
            rotate(x);
            continue;
        }
        rotate(t[x].f);
        rotate(x);
    }
}
int find(int x,int val)
{
    pushdown(x);
    if(val==t[t[x].son[0]].sum+1)
    {
        return x;
    }
    else if(val<=t[t[x].son[0]].sum)
    {
        return find(t[x].son[0],val);
    }
    else
    {
        return find(t[x].son[1],val-t[t[x].son[0]].sum-1);
    }
}
void print(int x,int rev=0)
{
    if(!x)
    {
        return;
    }
    pushdown(x);
    if(t[x].rev)
    {
        rev^=1;
    }
    if(rev)
    {
        swap(t[x].son[0],t[x].son[1]);
    }
    print(t[x].son[0],rev);
    printf("%d ",x);
    print(t[x].son[1],rev); 
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    root=1;
    for(int i=1;i<=n;i++)
    {
        t[i].f=i-1;
        t[t[i].f].son[1]=i;
        t[i].val=i;
        t[i].num=1;
        t[i].sum=n-i+1;
    }
    while(m--)
    {
        int l,r;
        scanf("%d%d",&l,&r);
        if(l==1&&r==n)
        {
            pushrev(root);
            continue;
        }
        if(l==1)
        {
            splay(find(root,r+1));
            pushdown(root);
            int tmp=t[root].son[0];
            pushrev(tmp);
            continue;
        }
        if(r==n)
        {
            splay(find(root,l-1));
            pushdown(root);
            int tmp=t[root].son[1];
            pushrev(tmp);
            continue;
        }
        splay(find(root,l-1));
        splay(find(root,r+1));
        pushdown(root);
        pushdown(t[root].son[0]);
        int tmp1=t[root].son[0];
        int tmp=t[tmp1].son[1];
        pushrev(tmp);
    }
    print(root);
    return 0;
}
